<template>
  <v-card v-if="isOpen" elevation="2">
    <v-toolbar>
      <v-toolbar-title class="text-truncate" style="max-width: 100px;">Salidas</v-toolbar-title>
      <v-divider class="mx-2" inset vertical></v-divider>
      <div class="font-weight-bold" style="font-size: 16px;">{{ localIssue.code }} </div>
      <v-spacer></v-spacer>
    </v-toolbar>
    <v-card-text>
      <v-form ref="formRef" v-model="valid">
        <v-row align="center">
          <v-col cols="12" md="2">
            <v-select v-if="!localIssue.idIssue" color="indigo" variant="outlined" density="compact"
              v-model="localIssue.type" :items="issueTypes" label="Tipo de Salida" :rules="[rules.required]" />
            <v-text-field v-else color="indigo" variant="outlined" density="compact" v-model="localIssue.type"
              label="Tipo de salida" readonly />
          </v-col>
          <v-col v-if="localIssue.type === 'Consignación'" cols="12" md="2">
            <v-autocomplete v-if="!localIssue.idIssue" color="indigo" variant="outlined" density="compact"
              :items="usersArray" v-model="localIssue.idUser" item-title="userName" item-value="idUser"
              :rules="[rules.required]" no-data-text="No hay datos disponibles" label="Personal"
              :loading="loadingUsers" />
            <v-text-field v-else color="indigo" variant="outlined" density="compact" v-model="localIssue.userName"
              label="Personal" readonly />
          </v-col>
          <v-col v-if="!localIssue.idIssue" cols="12" md="2" style="padding-bottom: 22px;">
            <v-tooltip v-bind="tooltipProps" text="Seleccionar Producto" location="bottom">
              <template v-slot:activator="{ props }">
                <v-btn v-bind="props" fab dark color="indigo" @click="openProductModal">
                  <v-icon icon="mdi-playlist-plus" size="24"></v-icon>
                </v-btn>
              </template>
            </v-tooltip>
          </v-col>
        </v-row>
        <v-divider class="mb-4 mt-1"></v-divider>
        <v-data-table :headers="headers" :items="details" class="elevation-1" hide-default-footer
          :no-data-text="'No hay productos agregados'">
          <template v-slot:item="{ item, index }">
            <tr>
              <td class="text-center">{{ index + 1 }}</td>
              <td class="text-center">{{ item.code }}</td>
              <td class="text-center">{{ item.description }}</td>
              <td class="text-center">{{ item.material }}</td>
              <td class="text-center">{{ item.color }}</td>
              <td class="text-center">{{ item.categoryName }}</td>
              <td class="text-center">{{ item.brandName }}</td>
              <td v-if="!localIssue.idIssue">
                <v-text-field v-model.number="item.quantity" variant="outlined" type="number" min="0" density="compact"
                  hide-details
                  :error="item.quantity <= 0 || item.quantity === null || item.quantity > item.stockAvailable"
                  :rules="[rules.requiredNumber, rules.minValue, rules.maxStock(item)]"></v-text-field>
              </td>
              <td class="text-center" v-else>{{ item.quantity }}</td>
              <td v-if="!localIssue.idIssue">
                <v-text-field v-model.number="item.unitPrice" variant="outlined" type="number" min="0" density="compact"
                  hide-details style="min-width: 60px;" :error="item.unitPrice < 0 || item.unitPrice === null"
                  :rules="[rules.requiredNumber, rules.minValueOrZero]"></v-text-field>
              </td>
              <td class="text-center" v-else>{{ formatCurrency(item.unitPrice) }}</td>
              <td class="text-center" v-if="!localIssue.idIssue">{{ formatCurrency(item.quantity * item.unitPrice) }}
              </td>
              <td class="text-center" v-else>{{ formatCurrency(item.totalPrice) }}</td>
              <td v-if="!localIssue.idIssue" class="text-center">
                <v-tooltip v-bind="tooltipProps" text="Quitar" location="bottom">
                  <template v-slot:activator="{ props }">
                    <v-btn v-bind="props" icon variant="text" color="red" size="small" @click="removeProduct(item)">
                      <v-icon icon="mdi-minus-circle-outline" size="24"></v-icon>
                    </v-btn>
                  </template>
                </v-tooltip>
              </td>
            </tr>
          </template>
        </v-data-table>
        <v-col v-if="!localIssue.idIssue" cols="12" class="d-flex justify-end mt-4 pr-4">
          <strong>Total Bs.</strong>{{ formatCurrency(total) }}
        </v-col>
        <v-col v-else cols="12" class="d-flex justify-end mt-4 pr-4">
          <strong>Total Bs.</strong>{{ formatCurrency(localIssue.totalAmount) }}
        </v-col>
        <div v-if="detailErrors.length > 0" class="mt-2 mb-1 px-2">
          <div v-for="(err, i) in detailErrors" :key="i" class="text-error text-caption">
            • {{ err }}
          </div>
        </div>
        <v-col cols="12">
          <v-text-field color="indigo" variant="underlined" label="Observaciones" counter="80" :maxlength="80"
            v-model="localIssue.annotations" :readonly="!!localIssue.idIssue"></v-text-field>
        </v-col>
      </v-form>
    </v-card-text>
    <v-card-actions class="px-4 pb-4 pt-0" justify="end">
      <v-btn v-if="!localIssue.idIssue" color="green" dark elevation="4" @click="saveIssue"
        :disabled="!valid || details.length === 0" :loading="saving">
        Guardar
      </v-btn>
      <v-btn v-else-if="localIssue.statusIssue === 'Activo' && canDownload" color="indigo" dark elevation="4"
        @click="downloadPdf" :loading="downloading">
        Descargar
      </v-btn>
      <v-btn color="red" dark elevation="4" @click="close">
        {{ localIssue.idIssue ? 'Cerrar' : 'Cancelar' }}
      </v-btn>
    </v-card-actions>
    <CommonProductOut v-model="productModal" @close="productModal = false" @product-added="handleProductAdded" />
  </v-card>
</template>

<script setup lang="ts">
import { ref, computed, watch, onMounted } from 'vue';
import { storeToRefs } from 'pinia';
import { useToast } from 'vue-toastification';
import { useGoodsIssueStore } from '@/stores/goodsIssueStore';
import { useUserStore } from '@/stores/userStore';
import { useAuthStore } from '@/stores/auth';
import { handleApiError } from '@/helpers/errorHandler';
import CommonProductOut from '@/components/Common/CommonProductOut.vue';
import { formatCurrency } from '@/utils/currency';
import { GoodsIssue, GoodsIssueDetail } from '@/interfaces/goodsIssueInterface';
import { useResponsiveTooltip } from '@/composables/useResponsiveTooltip';

interface FormRef {
  validate: () => boolean;
}

interface Props {
  modelValue: boolean;
  issue?: GoodsIssue | null;
  issueDetails?: GoodsIssueDetail[];
}

const props = withDefaults(defineProps<Props>(), {
  issue: () => ({
    idIssue: null,
    code: '',
    type: '',
    storeName: '',
    idUser: null,
    userName: '',
    totalAmount: 0,
    annotations: '',
    auditCreateDate: '',
    statusIssue: ''
  } as GoodsIssue),
  issueDetails: () => []
});

const emit = defineEmits<{
  'update:modelValue': [value: boolean];
  'saved': [];
  'close': [];
}>();

const goodsIssueStore = useGoodsIssueStore();
const userStore = useUserStore();
const authStore = useAuthStore();
const toast = useToast();

const canDownload = computed(() => authStore.hasPermission('salida de productos', 'descargar'));

const { users, loading: loadingUsers } = storeToRefs(userStore);

const formRef = ref<FormRef | null>(null);
const isOpen = ref(props.modelValue);
const valid = ref(false);
const saving = ref(false);
const downloading = ref(false);
const productModal = ref(false);
const localIssue = ref<GoodsIssue>({ ...props.issue } as GoodsIssue);
const details = ref<GoodsIssueDetail[]>([]);
const { tooltipProps } = useResponsiveTooltip();

const issueTypes = ['Consignación', 'Baja', 'Ajuste de inventario', 'Ajuste de kardex'];

const rules = {
  required: (value: any) => !!value || 'Este campo es requerido',
  requiredNumber: (value: any) => (value !== null && value !== undefined && value !== '') || 'Este campo es requerido',
  minValue: (value: number) => value > 0,
  minValueOrZero: (value: number) => (value !== null && value !== undefined && value >= 0),
  maxStock: (item: GoodsIssueDetail) => (value: number) => value <= item.stockAvailable
  //maxStock: (item: GoodsIssueDetail) => (value: number) => value <= item.stockAvailable || `Máximo disponible: ${item.stockAvailable}`
};

const headers = computed(() => {
  const baseHeaders: Array<{ title: string; key: string; sortable: boolean; align?: 'start' | 'end' | 'center', width?: string }> = [
    { title: 'Item', key: 'item', sortable: false, align: 'center', width: '100px' },
    { title: 'Código', key: 'code', sortable: false, align: 'center' },
    { title: 'Descripción', key: 'description', sortable: false, align: 'center' },
    { title: 'Material', key: 'material', sortable: false, align: 'center' },
    { title: 'Color', key: 'color', sortable: false, align: 'center' },
    { title: 'Categoría', key: 'categoryName', sortable: false, align: 'center' },
    { title: 'Marca', key: 'brandName', sortable: false, align: 'center' },
    { title: 'Cantidad', key: 'quantity', sortable: false, align: 'center', width: '120px' },
    { title: 'Precio', key: 'price', sortable: false, align: 'center', width: '120px' },
    { title: 'SubTotal', key: 'subtotal', sortable: false, align: 'center', width: '100px' }
  ];

  if (!localIssue.value.idIssue) {
    baseHeaders.push({ title: 'Acciones', key: 'actions', sortable: false, align: 'center', width: '150px' });
  }

  return baseHeaders;
});

const detailErrors = computed(() => {
  const errors: string[] = [];
  details.value.forEach((item, index) => {
    if (!item.quantity || item.quantity <= 0) {
      errors.push(`Fila ${index + 1} (con código: ${item.code}): La cantidad debe ser mayor a 0`);
    } else if (item.quantity > item.stockAvailable) {
      errors.push(`Fila ${index + 1} (con código: ${item.code}): Máximo disponible: ${item.stockAvailable}`);
    }
    if (item.unitPrice === null || item.unitPrice === undefined || item.unitPrice < 0) {
      errors.push(`Fila ${index + 1} (con código: ${item.code}): El precio debe ser mayor o igual a 0`);
    }
  });
  return errors;
});
const total = computed(() => {
  return details.value.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
});

const usersArray = computed(() => Array.isArray(users.value) ? users.value : []);

watch(() => props.modelValue, (newValue) => {
  isOpen.value = newValue;
});

watch(isOpen, (newValue) => {
  emit('update:modelValue', newValue);
});

watch(() => props.issue, (newIssue) => {
  if (newIssue) {
    localIssue.value = { ...newIssue };
  }
  details.value = [...props.issueDetails];
}, { deep: true });

const openProductModal = () => {
  productModal.value = true;
};

const handleProductAdded = (product: any) => {
  const exists = details.value.find(d => d.idProduct === product.idProduct);
  if (exists) {
    toast.warning('Este producto ya se encuentra en la lista');
    return;
  }

  if ((product.stockAvailable ?? 0) <= 0) {
    toast.warning('Este producto no cuenta con cantidad disponible');
    return;
  }

  details.value.push({
    idProduct: product.idProduct,
    code: product.code,
    description: product.description,
    material: product.material,
    color: product.color,
    categoryName: product.categoryName,
    brandName: product.brandName,
    quantity: 1,
    unitPrice: product.price,
    totalPrice: 0,
    stockAvailable: product.stockAvailable
  });

  toast.success('Producto agregado a la lista');
};

const removeProduct = (product: GoodsIssueDetail) => {
  const index = details.value.findIndex(d => d.idProduct === product.idProduct);

  if (index !== -1) {
    details.value.splice(index, 1);
    toast.error(`Producto ${product.code} eliminado de la lista`);
  }
};

const saveIssue = async () => {
  if (!formRef.value?.validate()) {
    toast.warning('Por favor completa todos los campos requeridos');
    return;
  }

  saving.value = true;

  try {
    const issueData = {
      type: localIssue.value.type,
      totalAmount: total.value,
      annotations: localIssue.value.annotations || '',
      idUser: localIssue.value.idUser,
      idStore: authStore.currentUser?.storeId,
      goodsIssueDetails: details.value.map((d, index) => ({
        item: index + 1,
        idProduct: d.idProduct,
        quantity: d.quantity,
        unitPrice: d.unitPrice,
        totalPrice: d.quantity * d.unitPrice
      }))
    };

    const result = await goodsIssueStore.registerGoodsIssue(issueData);

    if (result.isSuccess) {
      toast.success('Salida registrada con éxito');
      emit('saved');
      close();
    }
  } catch (error) {
    handleApiError(error, 'Error al registrar la salida');
  } finally {
    saving.value = false;
  }
};

const downloadPdf = async () => {
  if (!localIssue.value.idIssue) return;

  downloading.value = true;
  try {
    await goodsIssueStore.exportGoodsIssuePdf(localIssue.value.idIssue);
    toast.success('PDF descargado correctamente');
  } catch (error) {
    handleApiError(error, 'Error al descargar el PDF');
  } finally {
    downloading.value = false;
  }
};

const close = () => {
  isOpen.value = false;
  emit('close');
};

onMounted(() => {
  details.value = [...props.issueDetails];
  userStore.selectUser();
});
</script>